classDiagram
    class Observable {
        +observers: list
        +subscribe(observer)
        +unsubscribe(observer)
        +notify(event)
    }
    class Observer {
        +on_event(event)
    }
    class EventBus {
        +publish(topic, data)
        +subscribe(topic, handler)
    }
    Observable --> Observer : notifies
    EventBus --|> Observable

classDiagram
    class User {
        +id: int
        +email: str
        +hashed_password: str
        +is_active: bool
        +created_at: datetime
    }
    class UserCreate {
        +email: str
        +password: str
    }
    class UserResponse {
        +id: int
        +email: str
        +is_active: bool
    }
    class UserService {
        +create_user(data)
        +get_user(id)
        +authenticate(email, password)
    }
    UserService --> User
    UserCreate ..> User : creates
    User ..> UserResponse : serializes
